SELECT h.*, ste.site_nm AS site_nm, usr.user_nm AS chg_user_nm FROM odh_dliv_item_chg_hist h LEFT JOIN sy_site ste ON ste.site_id = h.site_id LEFT JOIN sy_user usr ON usr.user_id = h.chg_user_id
ORDER BY h.dliv_item_chg_hist_id ASC ORDER BY h.dliv_item_chg_hist_id DESC ORDER BY h.reg_date ASC ORDER BY h.reg_date DESC ORDER BY h.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

